-- deployment: Creating vw_order_summary...
CREATE VIEW vw_order_summary AS select `sale_order`.`id` AS `id`,`sale_order`.`order_num` AS `order_num`,`sale_order`.`username` AS `username`,`sale_order`.`customer_id` AS `customer_id`,`sale_order`.`order_status` AS `order_status`,`sale_order`.`total_price` AS `total_price`,`sale_order`.`total_mrp` AS `total_mrp`,`sale_order`.`final_price` AS `final_price`,`sale_order`.`total_items` AS `total_items`,`sale_order`.`total_qty` AS `total_qty`,`sale_order`.`disc_amount` AS `disc_amount`,`sale_order`.`coupon_disc_amount` AS `coupon_disc_amount`,`sale_order`.`tax_amount` AS `tax_amount`,`sale_order`.`shipping_charge` AS `shipping_charge`,`sale_order`.`payment_status` AS `payment_status`,`sale_order`.`payment_method` AS `payment_method`,`sale_order`.`placed_on` AS `placed_on`,`sale_order`.`invoice_file_id` AS `invoice_file_id`,`sale_order`.`return_term` AS `return_term`,`sale_order`.`order_rating` AS `order_rating`,`sale_order`.`awb_code` AS `awb_code` from `sale_order`;


