-- deployment: Creating vw_user_summary...
CREATE VIEW vw_user_summary AS select `um`.`id` AS `id`,`um`.`username` AS `username`,`um`.`display_name` AS `display_name`,`um`.`email_id` AS `email_id`,`um`.`mobile_number` AS `mobile_number`,`fm`.`url` AS `avatar_url`,`um`.`reset_reqd` AS `reset_reqd`,`um`.`status` AS `status`,`um`.`twofactor_enabled` AS `twofactor_enabled`,`um`.`twofactor_type` AS `twofactor_type`,`um`.`twofactor_value` AS `twofactor_value` from (`sec_user_master` `um` left join `cdn_file_master` `fm` on((`um`.`avatar_file_id` = `fm`.`id`)));


-- deployment: Creating vw_customer_summary...
CREATE VIEW vw_customer_summary AS select `cm`.`id` AS `id`,`cm`.`uhid` AS `uhid`,`cm`.`first_name` AS `first_name`,`cm`.`middle_name` AS `middle_name`,`cm`.`last_name` AS `last_name`,`cm`.`username` AS `username`,`cm`.`gender` AS `gender`,`cm`.`dob` AS `dob`,`cm`.`mobile_number` AS `mobile_number`,`cm`.`email_id` AS `email_id`,`cm`.`referred_by` AS `referred_by`,`cm`.`registered_on` AS `registered_on`,`cm`.`parent_id` AS `parent_id`,`cm`.`prefered_communication` AS `prefered_communication`,`cm`.`blood_group` AS `blood_group`,`cm`.`height_cm` AS `height_cm`,`cm`.`weight_kgs` AS `weight_kgs`,`cm`.`profile_setup_required` AS `profile_setup_required`,(case when (`um`.`password` is null) then 1 else 0 end) AS `is_password_exist`,`fm`.`url` AS `avatar_url` from ((`customer_master` `cm` left join `sec_user_master` `um` on((`um`.`username` = `cm`.`username`))) left join `cdn_file_master` `fm` on((`um`.`avatar_file_id` = `fm`.`id`)));


